class LFUCache:
    def __init__(self, capacity):
        self.cache = {}
        self.count = {}
        for i in range(capacity):
            self.cache[i] = (0, 0)

    def get(self, key):
        if key not in self.cache:
            return -1
        count, value = self.cache[key]
        self.cache[key] = (count + 1, value)
        self.count[key] = count + 1
        return value

    def put(self, key, value):
        if key in self.cache:
            del self.cache[key]
        else:
            count, value = self.cache[key]
            self.cache[key] = (count + 1, value)
            self.count[key] = count + 1
            return value
```

